// WhatsApp Webhook Message Parser
// Normalizes incoming webhook payload into standard format { phone, message_type, message_body, media_id, is_media, timestamp }

const rawData = $input.first().json;

// 1) Check for WhatsApp Cloud API GET verification handshake
// In n8n, GET query params may appear directly or nested under "query"
const hubMode = rawData.hub?.mode || rawData.query?.hub?.mode || '';
const hubToken = rawData.hub?.['verify_token'] || rawData.query?.hub?.['verify_token'] || '';
const hubChallenge = rawData.hub?.challenge || rawData.query?.hub?.challenge || '';

if (hubMode === 'subscribe') {
  const expectedToken = process.env.WHATSAPP_VERIFY_TOKEN || '';
  const verified = hubToken === expectedToken;
  return [
    {
      json: {
        isVerification: true,
        verified: verified,
        challenge: verified ? hubChallenge : 'Verification failed - token mismatch'
      }
    }
  ];
}

// 2) Check for POST with WhatsApp message payload
if (rawData.entry && Array.isArray(rawData.entry) && rawData.entry.length > 0) {
  const entry = rawData.entry[0];
  if (entry.changes && Array.isArray(entry.changes) && entry.changes.length > 0) {
    const change = entry.changes[0];
    const value = change.value || {};

    // Discard status updates (no messages array)
    if (!value.messages || !Array.isArray(value.messages) || value.messages.length === 0) {
      return [
        {
          json: {
            isStatusUpdate: true
          }
        }
      ];
    }

    const msg = value.messages[0];
    const contact = value.contacts && value.contacts.length > 0 ? value.contacts[0] : null;
    const messageType = msg.type || 'text';

    // Extract message body based on type
    let messageBody = '';
    let mediaId = '';

    if (messageType === 'text' && msg.text) {
      messageBody = msg.text.body || '';
    } else if (messageType === 'image' && msg.image) {
      messageBody = msg.image.caption || '';
      mediaId = msg.image.id || '';
    } else if (messageType === 'document' && msg.document) {
      messageBody = msg.document.caption || '';
      mediaId = msg.document.id || '';
    } else if (messageType === 'audio' && msg.audio) {
      mediaId = msg.audio.id || '';
    } else if (messageType === 'video' && msg.video) {
      mediaId = msg.video.id || '';
    }

    return [
      {
        json: {
          isVerification: false,
          isStatusUpdate: false,
          phone: msg.from || '',
          message_type: messageType,
          message_body: messageBody,
          media_id: mediaId,
          is_media: messageType !== 'text',
          message_id: msg.id || '',
          timestamp: msg.timestamp || String(Math.floor(Date.now() / 1000)),
          profile_name: contact ? contact.profile?.name || '' : ''
        }
      }
    ];
  }
}

// 3) Unknown payload format — treat as status update to avoid errors
return [
  {
    json: {
      isStatusUpdate: true
    }
  }
];

// Session Manager
// Reads/writes sessions via n8n Data Store ($dataStore)
// Key: session:{phone}, TTL: 1800 (30 minutes)
// Creates new session with state:START if none exists
// If expired (30min) → delete and re-create

const data = $input.first().json;

// Pass through verification and status updates (no session needed)
if (data.isVerification) {
  return [{ json: { ...data, session: null } }];
}
if (data.isStatusUpdate) {
  return [{ json: { ...data, session: null } }];
}

const phone = data.phone;
if (!phone) {
  return [{ json: { ...data, session: null, error: 'No phone number provided' } }];
}

const sessionKey = `session:${phone}`;

// Try to load existing session from Data Store
let session = null;
try {
  session = await $dataStore.get(sessionKey);
} catch (e) {
  // Data Store unavailable or key doesn't exist
  session = null;
}

const now = new Date();

// If session exists, check expiry (30 minutes)
if (session) {
  const updatedAt = new Date(session.updated_at).getTime();
  const thirtyMinutesAgo = now.getTime() - (30 * 60 * 1000);

  if (updatedAt < thirtyMinutesAgo) {
    // Session expired — delete and re-create
    try {
      await $dataStore.delete(sessionKey);
    } catch (e) {
      // Ignore deletion errors
    }
    session = null;
  }
}

// Create new session if none exists or was expired
if (!session) {
  session = {
    phone: phone,
    name: '',
    email: '',
    state: 'START',
    participant_id: '',
    retry_count: 0,
    created_at: now.toISOString(),
    updated_at: now.toISOString()
  };

  try {
    await $dataStore.set(sessionKey, session, { ttl: 1800 });
  } catch (e) {
    console.error('Failed to create session:', e);
  }
} else {
  // Update timestamp to keep session alive
  session.updated_at = now.toISOString();
  try {
    await $dataStore.set(sessionKey, session, { ttl: 1800 });
  } catch (e) {
    console.error('Failed to update session:', e);
  }
}

return [
  {
    json: {
      ...data,
      session: session,
      sessionKey: sessionKey
    }
  }
];

// Welcome Handler
// START state: send welcome message and transition to WAIT_PHONE

const data = $input.first().json;

if (!data.session) {
  return [{ json: { ...data, replyMessage: '', action: 'noop' } }];
}

// Update session: state → WAIT_PHONE, reset retry
const session = { ...data.session };
session.state = 'WAIT_PHONE';
session.retry_count = 0;
session.updated_at = new Date().toISOString();

return [
  {
    json: {
      ...data,
      session: session,
      replyMessage: 'Bienvenido a Superlikers. Para participar en nuestra promocion, por favor indica tu numero de telefono a 10 digitos.',
      action: 'welcome'
    }
  }
];

// Phone Validator
// Output 0: valid phone number → continues to Search Participant
// Output 1: invalid phone number → routes to error handling
// Validates: 10 digits (Colombia), strips non-numeric, normalizes with COUNTRY_CODE prefix

const COUNTRY_CODE = process.env.COUNTRY_CODE || '57';
const PHONE_DIGITS = parseInt(process.env.PHONE_DIGITS || '10', 10);

const data = $input.first().json;
let rawPhone = data.message_body || '';

// Strip all non-numeric characters
const digits = rawPhone.replace(/\D/g, '');

if (digits.length !== PHONE_DIGITS) {
  // INVALID — output 1
  return [
    [],
    [
      {
        json: {
          ...data,
          valid: false,
          phone: null,
          normalizedPhone: null,
          error: `El numero debe tener exactamente ${PHONE_DIGITS} digitos. Recibimos ${digits.length} digitos. Intenta de nuevo.`
        }
      }
    ]
  ];
}

// VALID — output 0
const normalizedPhone = `+${COUNTRY_CODE}${digits}`;

return [
  [
    {
      json: {
        ...data,
        valid: true,
        phone: normalizedPhone,
        normalizedPhone: normalizedPhone,
        rawInput: rawPhone
      }
    }
  ],
  []
];

// Session Update
// Applies partial updates to session and persists to Data Store
// Resets retry_count on state change
// Saves with TTL 1800

const data = $input.first().json;

// Pass through verification and status updates
if (data.isVerification || data.isStatusUpdate) {
  return [{ json: data }];
}

let session = data.session ? { ...data.session } : null;
if (!session) {
  return [{ json: data }];
}

const phone = data.normalizedPhone || data.phone || session.phone || '';
const sessionKey = `session:${phone}`;

// Determine what updates to apply based on action + context
const previousState = session.state;

if (data.action === 'welcome') {
  // Welcome Handler already updated state to WAIT_PHONE — persist
} else if (data.valid === false) {
  // Phone validation failed — increment retry, keep current state
  session.retry_count = (session.retry_count || 0) + 1;
} else if (data.valid === true && phone) {
  // Phone validated successfully — update phone, stay in current state
  session.phone = phone;
  // State changes happen AFTER the HTTP search, not here
} else if (data.statusCode === 200 && data.body) {
  // Participant found via API
  const participant = typeof data.body === 'object' ? data.body : {};
  session.state = 'WAIT_TICKET';
  session.retry_count = 0;
  session.participant_id = participant.id || participant.participant_id || '';
  session.name = participant.name || '';
  session.email = participant.email || '';
  session.phone = phone || session.phone;
} else if (data.statusCode === 404) {
  // Participant not found — proceed to registration flow
  session.state = 'WAIT_NAME';
  session.retry_count = 0;
} else if (data.statusCode >= 400) {
  // API error (500, 429, etc.) — increment retry, keep state
  session.retry_count = (session.retry_count || 0) + 1;
}

// Reset retry_count on state change
if (session.state !== previousState && previousState) {
  session.retry_count = 0;
}

// Always update timestamp
session.updated_at = new Date().toISOString();

// Persist to Data Store
if (phone) {
  try {
    await $dataStore.set(sessionKey, session, { ttl: 1800 });
  } catch (e) {
    console.error('Failed to update session in Data Store:', e);
  }
}

return [
  {
    json: {
      ...data,
      session: session
    }
  }
];

// Message Builder
// Builds WhatsApp message payload from the current state and context
// Returns: { to, type, text: { body } }
// This is the last node in the chain — its output becomes the webhook response

const data = $input.first().json;

// 1) Handle GET verification — return challenge as plain text response
if (data.isVerification) {
  return [
    {
      json: {
        to: '',
        type: 'text',
        text: {
          body: data.challenge || 'Verification failed'
        }
      }
    }
  ];
}

// 2) Handle status updates — return empty 200
if (data.isStatusUpdate) {
  return [
    {
      json: {
        to: '',
        type: 'none',
        text: {
          body: 'ok'
        }
      }
    }
  ];
}

const phone = data.normalizedPhone || data.phone || '';
const session = data.session || {};

// 3) Use explicit replyMessage if set by a handler
let replyBody = data.replyMessage || '';

// 4) If no replyMessage was set, generate based on session state
if (!replyBody && session.state) {
  switch (session.state) {
    case 'WAIT_PHONE':
      replyBody = 'Por favor indica tu numero de telefono a 10 digitos.';
      break;
    case 'WAIT_NAME':
      replyBody = 'No encontramos tu registro. Por favor indicame tu nombre completo.';
      break;
    case 'WAIT_EMAIL':
      replyBody = 'Gracias. Ahora indicame tu correo electronico.';
      break;
    case 'WAIT_CONFIRMATION':
      replyBody = 'Confirma que los datos ingresados son correctos. Responde Si o No.';
      break;
    case 'WAIT_TICKET':
      replyBody = 'Ya encontramos tu registro. Ahora enviame una foto de tu ticket.';
      break;
    default:
      replyBody = 'Gracias por tu mensaje. Te responderemos pronto.';
  }
}

// 5) If there was an error (phone validation, etc.), use it
if (!replyBody && data.error) {
  replyBody = data.error;
}

return [
  {
    json: {
      to: phone,
      type: 'text',
      text: {
        body: replyBody || 'Gracias por tu mensaje. Te responderemos pronto.'
      }
    }
  }
];
